enum DeviceIntegrityLevel {
  trusted,
  suspicious,
  compromised,
}

class DeviceIntegrityResult {
  final DeviceIntegrityLevel level;
  final List<String> issues;
  final Map<String, dynamic> metadata;

  DeviceIntegrityResult({
    required this.level,
    required this.issues,
    required this.metadata,
  });

  bool get isTrusted => level == DeviceIntegrityLevel.trusted;
  bool get isCompromised => level == DeviceIntegrityLevel.compromised;
}

class DeviceIntegrityChecker {
  static const MethodChannel _channel = MethodChannel('secure_payment/integrity');
  
  static Future<DeviceIntegrityResult> performIntegrityCheck() async {
    final List<String> issues = [];
    final Map<String, dynamic> metadata = {};

    try {
      // Multi-layered integrity checks
      final rootCheck = await _checkRootJailbreak();
      final debugCheck = await _checkDebugMode();
      final emulatorCheck = await _checkEmulator();
      final tamperCheck = await _checkAppTamper();
      final hookCheck = await _checkFrameworkHooks();
      
      metadata['root_detected'] = rootCheck;
      metadata['debug_mode'] = debugCheck;
      metadata['emulator'] = emulatorCheck;
      metadata['tampered'] = tamperCheck;
      metadata['hooks_detected'] = hookCheck;

      if (rootCheck) issues.add('Root/Jailbreak detected');
      if (debugCheck) issues.add('Debug mode active');
      if (emulatorCheck) issues.add('Emulator detected');
      if (tamperCheck) issues.add('App tampering detected');
      if (hookCheck) issues.add('Framework hooks detected');

      // Determine integrity level based on severity
      DeviceIntegrityLevel level;
      if (rootCheck || tamperCheck || hookCheck) {
        level = DeviceIntegrityLevel.compromised;
      } else if (debugCheck || emulatorCheck) {
        level = DeviceIntegrityLevel.suspicious;
      } else {
        level = DeviceIntegrityLevel.trusted;
      }

      return DeviceIntegrityResult(
        level: level,
        issues: issues,
        metadata: metadata,
      );
    } catch (e) {
      // On error, assume compromised for security
      return DeviceIntegrityResult(
        level: DeviceIntegrityLevel.compromised,
        issues: ['Integrity check failed: $e'],
        metadata: {'error': e.toString()},
      );
    }
  }

  static Future<bool> _checkRootJailbreak() async {
    try {
      final result = await _channel.invokeMethod<bool>('checkRootJailbreak');
      return result ?? false;
    } catch (e) {
      return false;
    }
  }

  static Future<bool> _checkDebugMode() async {
    try {
      return kDebugMode || await _channel.invokeMethod<bool>('isDebuggable') == true;
    } catch (e) {
      return false;
    }
  }

  static Future<bool> _checkEmulator() async {
    try {
      final deviceInfo = DeviceInfoPlugin();
      if (Platform.isAndroid) {
        final androidInfo = await deviceInfo.androidInfo;
        final suspicious = androidInfo.isPhysicalDevice == false ||
            androidInfo.fingerprint.contains('generic') ||
            androidInfo.model.contains('Emulator');
        return suspicious;
      } else if (Platform.isIOS) {
        final iosInfo = await deviceInfo.iosInfo;
        return iosInfo.isPhysicalDevice == false;
      }
      return false;
    } catch (e) {
      return false;
    }
  }

  static Future<bool> _checkAppTamper() async {
    try {
      final result = await _channel.invokeMethod<bool>('checkSignature');
      return result == false;
    } catch (e) {
      return false;
    }
  }

  static Future<bool> _checkFrameworkHooks() async {
    try {
      final result = await _channel.invokeMethod<bool>('detectHooks');
      return result ?? false;
    } catch (e) {
      return false;
    }
  }
}

