class SecureTransactionContext {
  final String sessionId;
  final DateTime timestamp;
  final DeviceIntegrityResult integrityResult;
  final String deviceFingerprint;
  final bool biometricVerified;

  SecureTransactionContext({
    required this.sessionId,
    required this.timestamp,
    required this.integrityResult,
    required this.deviceFingerprint,
    required this.biometricVerified,
  });

  Map<String, dynamic> toSecurePayload() {
    return {
      'session_id': sessionId,
      'timestamp': timestamp.toIso8601String(),
      'integrity_level': integrityResult.level.toString(),
      'device_fingerprint': deviceFingerprint,
      'biometric_verified': biometricVerified,
      'integrity_metadata': integrityResult.metadata,
    };
  }
}

