abstract class PaymentGateway {
  Future<PaymentTransaction> processPayment(
    PaymentRequest request,
    SecureTransactionContext context,
  );
  
  Future<PaymentTransaction> refundTransaction(
    String transactionId,
    double amount,
    SecureTransactionContext context,
  );
  
  Future<PaymentTransaction> getTransactionStatus(String transactionId);
}

