class StripePaymentGateway implements PaymentGateway {
  final String publishableKey;
  final String secretKey;
  final bool isProduction;
  static const MethodChannel _channel = MethodChannel('secure_payment/stripe');

  StripePaymentGateway({
    required this.publishableKey,
    required this.secretKey,
    this.isProduction = false,
  });

  @override
  Future<PaymentTransaction> processPayment(
    PaymentRequest request,
    SecureTransactionContext context,
  ) async {
    try {
      final payload = {
        'amount': (request.amount * 100).toInt(),
        'currency': request.currency,
        'order_id': request.orderId,
        'publishable_key': publishableKey,
        'customer_data': request.customerData,
        'metadata': {
          ...request.metadata,
          ...context.toSecurePayload(),
        },
      };

      final result = await _channel.invokeMethod<Map>('processPayment', payload);
      
      if (result == null) {
        throw Exception('Payment processing failed');
      }

      return PaymentTransaction(
        transactionId: result['transaction_id'] as String,
        orderId: request.orderId,
        amount: request.amount,
        currency: request.currency,
        method: request.method,
        status: _parseStatus(result['status'] as String),
        timestamp: DateTime.now(),
        metadata: Map<String, dynamic>.from(result['metadata'] ?? {}),
      );
    } catch (e) {
      return PaymentTransaction(
        transactionId: 'failed_${DateTime.now().millisecondsSinceEpoch}',
        orderId: request.orderId,
        amount: request.amount,
        currency: request.currency,
        method: request.method,
        status: TransactionStatus.failed,
        timestamp: DateTime.now(),
        metadata: {'error': e.toString()},
      );
    }
  }

  @override
  Future<PaymentTransaction> refundTransaction(
    String transactionId,
    double amount,
    SecureTransactionContext context,
  ) async {
    try {
      final payload = {
        'transaction_id': transactionId,
        'amount': (amount * 100).toInt(),
        'secret_key': secretKey,
        'context': context.toSecurePayload(),
      };

      final result = await _channel.invokeMethod<Map>('refundPayment', payload);
      
      if (result == null) {
        throw Exception('Refund processing failed');
      }

      return PaymentTransaction(
        transactionId: result['refund_id'] as String,
        orderId: result['order_id'] as String,
        amount: amount,
        currency: result['currency'] as String,
        method: PaymentMethod.creditCard,
        status: TransactionStatus.refunded,
        timestamp: DateTime.now(),
        metadata: Map<String, dynamic>.from(result['metadata'] ?? {}),
      );
    } catch (e) {
      throw Exception('Refund failed: $e');
    }
  }

  @override
  Future<PaymentTransaction> getTransactionStatus(String transactionId) async {
    try {
      final result = await _channel.invokeMethod<Map>('getTransactionStatus', {
        'transaction_id': transactionId,
        'secret_key': secretKey,
      });

      if (result == null) {
        throw Exception('Failed to retrieve transaction status');
      }

      return PaymentTransaction(
        transactionId: transactionId,
        orderId: result['order_id'] as String,
        amount: (result['amount'] as int) / 100.0,
        currency: result['currency'] as String,
        method: PaymentMethod.creditCard,
        status: _parseStatus(result['status'] as String),
        timestamp: DateTime.parse(result['timestamp'] as String),
        metadata: Map<String, dynamic>.from(result['metadata'] ?? {}),
      );
    } catch (e) {
      throw Exception('Failed to get transaction status: $e');
    }
  }

  TransactionStatus _parseStatus(String status) {
    switch (status.toLowerCase()) {
      case 'succeeded':
      case 'completed':
        return TransactionStatus.completed;
      case 'pending':
        return TransactionStatus.pending;
      case 'processing':
        return TransactionStatus.processing;
      case 'failed':
        return TransactionStatus.failed;
      case 'canceled':
      case 'cancelled':
        return TransactionStatus.cancelled;
      case 'refunded':
        return TransactionStatus.refunded;
      default:
        return TransactionStatus.failed;
    }
  }
}

