  ) async {
    try {
      final payload = {
        'product_id': productId,
        'context': context.toSecurePayload(),
      };

      final result = await _channel.invokeMethod<Map>('purchaseProduct', payload);
      
      if (result == null) {
        throw Exception('Purchase failed');
      }

      return PaymentTransaction(
        transactionId: result['transaction_id'] as String,
        orderId: result['order_id'] as String,
        amount: (result['amount'] as num).toDouble(),
        currency: result['currency'] as String,
        method: PaymentMethod.inAppPurchase,
        status: _parseIAPStatus(result['status'] as String),
        timestamp: DateTime.now(),
        metadata: Map<String, dynamic>.from(result['metadata'] ?? {}),
      );
    } catch (e) {
      throw Exception('Purchase failed: $e');
    }
  }

  Future<bool> restorePurchases(SecureTransactionContext context) async {
    try {
      final result = await _channel.invokeMethod<bool>('restorePurchases', {
        'context': context.toSecurePayload(),
      });
      return result ?? false;
    } catch (e) {
