class SecurePaymentProcessor {
  final PaymentGateway gateway;
  final InAppPurchaseHandler iapHandler;
  final MobileWalletHandler walletHandler;
  final LocalAuthentication localAuth;
  
  SecurePaymentProcessor({
    required this.gateway,
    InAppPurchaseHandler? iapHandler,
    MobileWalletHandler? walletHandler,
    LocalAuthentication? localAuth,
  })  : iapHandler = iapHandler ?? InAppPurchaseHandler(),
        walletHandler = walletHandler ?? MobileWalletHandler(),
        localAuth = localAuth ?? LocalAuthentication();

  Future<SecureTransactionContext> _createSecureContext() async {
    final integrityResult = await DeviceIntegrityChecker.performIntegrityCheck();
    final deviceFingerprint = await _generateDeviceFingerprint();
    final biometricVerified = await _verifyBiometric();

    return SecureTransactionContext(
      sessionId: _generateSessionId(),
      timestamp: DateTime.now(),
      integrityResult: integrityResult,
      deviceFingerprint: deviceFingerprint,
      biometricVerified: biometricVerified,
    );
  }

  Future<PaymentTransaction> processPayment(PaymentRequest request) async {
    final context = await _createSecureContext();

    // Defense-in-depth: Block high-risk transactions on compromised devices
    if (context.integrityResult.isCompromised) {
      return PaymentTransaction(
        transactionId: 'blocked_${DateTime.now().millisecondsSinceEpoch}',
        orderId: request.orderId,
        amount: request.amount,
        currency: request.currency,
        method: request.method,
        status: TransactionStatus.failed,
        timestamp: DateTime.now(),
        metadata: {
          'error': 'Transaction blocked due to device integrity issues',
          'issues': context.integrityResult.issues,
        },
      );
    }

    // Additional verification for suspicious devices
    if (context.integrityResult.level == DeviceIntegrityLevel.suspicious) {
      if (!context.biometricVerified) {
        return PaymentTransaction(
          transactionId: 'blocked_${DateTime.now().millisecondsSinceEpoch}',
          orderId: request.orderId,
          amount: request.amount,
          currency: request.currency,
          method: request.method,
          status: TransactionStatus.failed,
          timestamp: DateTime.now(),
          metadata: {
            'error': 'Additional authentication required',
            'requires_biometric': true,
          },
        );
      }
    }

    // Route to appropriate payment handler
    switch (request.method) {
      case PaymentMethod.inAppPurchase:
        return await iapHandler.purchaseProduct(
          request.metadata['product_id'] as String,
          context,
        );
      
      case PaymentMethod.applePay:
      case PaymentMethod.googlePay:
        return await walletHandler.processWalletPayment(request, context);
      
      case PaymentMethod.creditCard:
      case PaymentMethod.debitCard:
        return await gateway.processPayment(request, context);
      
      default:
        throw Exception('Unsupported payment method');
    }
  }

  Future<PaymentTransaction> refundTransaction(
    String transactionId,
    double amount,
  ) async {
    final context = await _createSecureContext();

    if (context.integrityResult.isCompromised) {
      throw Exception('Refund blocked due to device integrity issues');
    }

    return await gateway.refundTransaction(transactionId, amount, context);
  }

  Future<PaymentTransaction> getTransactionStatus(String transactionId) async {
    return await gateway.getTransactionStatus(transactionId);
  }

  Future<bool> _verifyBiometric() async {
    try {
      final canAuthenticate = await localAuth.canCheckBiometrics;
      if (!canAuthenticate) return false;

      return await localAuth.authenticate(
        localizedReason: 'Verify your identity for secure payment',
        options: const AuthenticationOptions(
          stickyAuth: true,
          biometricOnly: true,
        ),
      );
    } catch (e) {
      return false;
    }
  }

  Future<String> _generateDeviceFingerprint() async {
    try {
      final deviceInfo = DeviceInfoPlugin();
      final packageInfo = await PackageInfo.fromPlatform();
      
      String fingerprint;
      if (Platform.isAndroid) {
        final androidInfo = await deviceInfo.androidInfo;
        fingerprint = '${androidInfo.id}_${androidInfo.androidId}_${packageInfo.packageName}';
      } else if (Platform.isIOS) {
        final iosInfo = await deviceInfo.iosInfo;
        fingerprint = '${iosInfo.identifierForVendor}_${packageInfo.packageName}';
      } else {
        fingerprint = 'unknown_${DateTime.now().millisecondsSinceEpoch}';
      }

      final bytes = utf8.encode(fingerprint);
      final hash = sha256.convert(bytes);
      return hash.toString();
    } catch (e) {
      return 'error_${DateTime.now().millisecondsSinceEpoch}';
    }
  }

  String _generateSessionId() {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final random = DateTime.now().microsecondsSinceEpoch;
    final combined = '$timestamp$random';
    final bytes = utf8.encode(combined);
    final hash = sha256.convert(bytes);
    return hash.toString();
  }
}

