// ============================================================================
// PAYMENT SERVICE (High-level API)
// ============================================================================

class PaymentService {
  late final SecurePaymentProcessor _processor;
  final PaymentConfiguration config;

  PaymentService(this.config) {
    final gateway = StripePaymentGateway(
      publishableKey: config.stripePublishableKey,
      secretKey: config.stripeSecretKey,
      isProduction: config.isProduction,
    );

    _processor = SecurePaymentProcessor(gateway: gateway);
  }

  Future<PaymentTransaction> processCardPayment({
    required String orderId,
    required double amount,
    required String currency,
    Map<String, dynamic>? customerData,
    Map<String, dynamic>? metadata,
  }) async {
    final request = PaymentRequest(
      orderId: orderId,
      amount: amount,
      currency: currency,
      method: PaymentMethod.creditCard,
      customerData: customerData ?? {},
      metadata: metadata ?? {},
    );

    return await _processor.processPayment(request);
  }

  Future<PaymentTransaction> processWalletPayment({
    required String orderId,
    required double amount,
    required String currency,
    Map<String, dynamic>? metadata,
  }) async {
    final method = Platform.isIOS ? PaymentMethod.applePay : PaymentMethod.googlePay;
    
    final request = PaymentRequest(
      orderId: orderId,
      amount: amount,
      currency: currency,
      method: method,
      metadata: {
        'merchant_id': config.merchantId,
        ...?metadata,
      },
    );

    return await _processor.processPayment(request);
  }

  Future<PaymentTransaction> processInAppPurchase({
    required String productId,
    required String orderId,
  }) async {
    final request = PaymentRequest(
      orderId: orderId,
      amount: 0.0,
      currency: 'USD',
      method: PaymentMethod.inAppPurchase,
      metadata: {'product_id': productId},
    );

    return await _processor.processPayment(request);
  }

  Future<PaymentTransaction> refund({
    required String transactionId,
    required double amount,
  }) async {
    return await _processor.refundTransaction(transactionId, amount);
  }

  Future<PaymentTransaction> getTransactionStatus(String transactionId) async {
    return await _processor.getTransactionStatus(transactionId);
  }

  Future<bool> isWalletAvailable() async {
    return await _processor.walletHandler.isWalletAvailable();
  }

  Future<List<String>> getAvailableProducts() async {
    return await _processor.iapHandler.getAvailableProducts();
  }

  Future<bool> restorePurchases() async {
    final context = await _processor._createSecureContext();
    return await _processor.iapHandler.restorePurchases(context);
  }

  Future<DeviceIntegrityResult> checkDeviceIntegrity() async {
    return await DeviceIntegrityChecker.performIntegrityCheck();
  }
}

// ============================================================================
// USAGE EXAMPLE
// ============================================================================

void exampleUsage() async {
  final config = PaymentConfiguration(
    stripePublishableKey: 'pk_test_xxxxx',
    stripeSecretKey: 'sk_test_xxxxx',
    merchantId: 'merchant.com.example.app',
    isProduction: false,
  );

  final paymentService = PaymentService(config);

  // Check device integrity before processing
  final integrity = await paymentService.checkDeviceIntegrity();
  print('Device Integrity: ${integrity.level}');
  print('Issues: ${integrity.issues}');

  // Process card payment
  try {
    final transaction = await paymentService.processCardPayment(
      orderId: 'ORDER_123',
      amount: 99.99,
      currency: 'USD',
      customerData: {
        'email': 'customer@example.com',
        'name': 'John Doe',
      },
    );
    
    print('Transaction: ${transaction.transactionId}');
    print('Status: ${transaction.status}');
  } catch (e) {
    print('Payment failed: $e');
  }

  // Process wallet payment
  if (await paymentService.isWalletAvailable()) {
    try {
      final transaction = await paymentService.processWalletPayment(
        orderId: 'ORDER_124',
        amount: 49.99,
        currency: 'USD',
      );
      print('Wallet payment: ${transaction.transactionId}');
    } catch (e) {
      print('Wallet payment failed: $e');
    }
  }

  // Process in-app purchase
  try {
    final products = await paymentService.getAvailableProducts();
    if (products.isNotEmpty) {
      final transaction = await paymentService.processInAppPurchase(
        productId: products.first,
        orderId: 'ORDER_125',
      );
      print('IAP: ${transaction.transactionId}');
    }
  } catch (e) {
    print('IAP failed: $e');
  }
}